-#!/usr/bin/env node
-
-/**
- * Generates progressive-disclosure Agent Skills from built markdown output in dist/.
- *
- * Output structure:
- *   skills/
- *   ├── tenzir/
- *   │   ├── SKILL.md
- *   │   ├── guides/
- *   │   ├── tutorials/
- *   │   └── ...
- *   └── ocsf/
- *       ├── SKILL.md
- *       ├── index.md
- *       ├── introduction.md
- *       └── ...
- */
-
-import fs from "node:fs";
-import path from "node:path";
-import { pathToFileURL } from "node:url";
-
-const DOCS_URL_PREFIX = /^https?:\/\/docs\.tenzir\.com/;
-const OCSF_ROOT = "reference/ocsf";
-
-// Reference stays intentionally shallow in the main skill because operators,
-// functions, and OCSF each have their own progressive disclosure.
-const SECTION_MAX_LEVEL = {
-  Guides: 4,
-  Tutorials: 4,
-  Explanations: 4,
-  Integrations: 4,
-  Reference: 3,
-};
-
-const SKILL_TARGETS = [
-  {
-    name: "tenzir-docs",
-    description: "Data pipeline engine for security teams",
-    includeSourcePath(sourcePath) {
-      return !isOcsfSourcePath(sourcePath);
-    },
-    mapSourcePath(sourcePath) {
-      return sourcePath;
-    },
-  },
-  {
-    name: "ocsf",
-    description: "Open Cybersecurity Schema Framework reference",
-    includeSourcePath(sourcePath) {
-      return isOcsfSourcePath(sourcePath);
-    },
-    mapSourcePath(sourcePath) {
-      if (sourcePath === `${OCSF_ROOT}.md`) return "index.md";
-      if (sourcePath.startsWith(`${OCSF_ROOT}/`)) {
-        return sourcePath.slice(`${OCSF_ROOT}/`.length);
-      }
-      return null;
-    },
-  },
-];
-
-function isOcsfSourcePath(sourcePath) {
-  return (
-    sourcePath === `${OCSF_ROOT}.md` || sourcePath.startsWith(`${OCSF_ROOT}/`)
-  );
-}
-
-function getHeadingLevel(line) {
-  const match = line.match(/^(#{1,6})\s/);
-  return match ? match[1].length : 0;
-}
-
-function extractHeadingText(line) {
-  const linkMatch = line.match(/^#{1,6}\s+\[([^\]]+)\]/);
-  if (linkMatch) return linkMatch[1];
-
-  const plainMatch = line.match(/^#{1,6}\s+(.+)$/);
-  return plainMatch ? plainMatch[1] : null;
-}
-
-function extractHeadingHref(line) {
-  const match = line.match(/^#{1,6}\s+\[[^\]]+\]\(([^)]+)\)/);
-  return match ? match[1] : null;
-}
-
-function normalizeRelativePath(filePath) {
-  return filePath.split(path.sep).join("/");
-}
-
-function normalizeDocsHref(href) {
-  if (!href) return href;
-  return href.replace(DOCS_URL_PREFIX, "");
-}
-
-function toSourceMarkdownPath(href) {
-  if (!href) return null;
-
-  const normalized = normalizeDocsHref(href);
-
-  if (!normalized.startsWith("/")) return null;
-
-  const pathPart = normalized.slice(1).split("#")[0].split("?")[0];
-  return pathPart.endsWith(".md") ? pathPart : null;
-}
-
-function getNodeSourcePath(node) {
-  return toSourceMarkdownPath(extractHeadingHref(node.heading ?? ""));
-}
-
-function isBulletLine(line) {
-  return line.startsWith("- ") || line.startsWith("  - ");
-}
-
-function trimBlankLines(lines) {
-  let start = 0;
-  let end = lines.length;
-
-  while (start < end && lines[start]?.trim() === "") start++;
-  while (end > start && lines[end - 1]?.trim() === "") end--;
-
-  return lines.slice(start, end);
-}
-
-function hasMeaningfulContent(lines) {
-  return lines.some((line) => line.trim() !== "" && !isBulletLine(line));
-}
-
-function parseHeadingTree(markdown) {
-  const root = {
-    heading: null,
-    level: 0,
-    contentLines: [],
-    children: [],
-  };
-  const stack = [root];
-
-  for (const line of markdown.split("\n")) {
-    const level = getHeadingLevel(line);
-    if (level === 0) {
-      stack.at(-1).contentLines.push(line);
-      continue;
-    }
-
-    while (stack.at(-1).level >= level) {
-      stack.pop();
-    }
-
-    const node = {
-      heading: line,
-      level,
-      contentLines: [],
-      children: [],
-    };
-    stack.at(-1).children.push(node);
-    stack.push(node);
-  }
-
-  return root;
-}
-
-function filterNode(node, { includeSourcePath, maxDepth }) {
-  if (node.level > maxDepth) return null;
-
-  const sourcePath = getNodeSourcePath(node);
-  if (sourcePath && !includeSourcePath(sourcePath)) return null;
-
-  const children = node.children
-    .map((child) => filterNode(child, { includeSourcePath, maxDepth }))
-    .filter(Boolean);
-
-  if (
-    !children.length &&
-    !hasMeaningfulContent(node.contentLines) &&
-    !sourcePath
-  ) {
-    return null;
-  }
-
-  return {
-    ...node,
-    children,
-  };
-}
-
-function findNodeBySourcePath(node, sourcePath) {
-  if (getNodeSourcePath(node) === sourcePath) return node;
-
-  for (const child of node.children) {
-    const match = findNodeBySourcePath(child, sourcePath);
-    if (match) return match;
-  }
-
-  return null;
-}
-
-function rewriteLinkDestination(href, target, fromPath) {
-  if (
-    !href ||
-    href.startsWith("#") ||
-    href.startsWith("mailto:") ||
-    href.startsWith("tel:")
-  ) {
-    return href;
-  }
-
-  const normalized = normalizeDocsHref(href);
-
-  if (!normalized.startsWith("/")) {
-    return href;
-  }
-
-  const hashIndex = normalized.indexOf("#");
-  const queryIndex = normalized.indexOf("?");
-  const suffixIndex =
-    hashIndex > -1 && queryIndex > -1
-      ? Math.min(hashIndex, queryIndex)
-      : hashIndex > -1
-        ? hashIndex
-        : queryIndex > -1
-          ? queryIndex
-          : normalized.length;
-
-  const pathname = normalized.slice(0, suffixIndex);
-  const suffix = normalized.slice(suffixIndex);
-  const sourcePath = pathname.slice(1);
-
-  if (!sourcePath.endsWith(".md")) {
-    return href;
-  }
-
-  if (!target.includeSourcePath(sourcePath)) {
-    return null;
-  }
-
-  const mappedPath = target.mapSourcePath(sourcePath);
-  if (!mappedPath) {
-    return null;
-  }
-
-  const fromDir =
-    path.posix.dirname(fromPath) === "." ? "" : path.posix.dirname(fromPath);
-  const relative =
-    path.posix.relative(fromDir || ".", mappedPath) || mappedPath;
-  return `${relative}${suffix}`;
-}
-
-function rewriteLinks(text, target, fromPath) {
-  return text.replace(
-    /(!?)\[([^\]]*)\]\(([^)]+)\)/g,
-    (_match, bang, label, href) => {
-      const rewrittenHref = rewriteLinkDestination(href, target, fromPath);
-      if (rewrittenHref === null) {
-        return bang ? `![${label}]` : label;
-      }
-      return `${bang}[${label}](${rewrittenHref})`;
-    },
-  );
-}
-
-function rewriteContent(text, target, fromPath) {
-  return rewriteLinks(
-    text.replace(/^> Documentation index:.*\n?/gm, ""),
-    target,
-    fromPath,
-  );
-}
-
-function renderNode(
-  node,
-  target,
-  { levelOffset = 0, fromPath = "SKILL.md" } = {},
-) {
-  const lines = [];
-
-  if (node.heading) {
-    const level = Math.max(1, Math.min(6, node.level + levelOffset));
-    const headingText = rewriteContent(node.heading, target, fromPath).replace(
-      /^#{1,6}/,
-      "#".repeat(level),
-    );
-    lines.push(headingText, "");
-  }
-
-  const contentLines = trimBlankLines(
-    node.contentLines
-      .filter((line) => !isBulletLine(line))
-      .map((line) => rewriteContent(line, target, fromPath)),
-  );
-  if (contentLines.length > 0) {
-    lines.push(...contentLines, "");
-  }
-
-  for (const child of node.children) {
-    const renderedChild = renderNode(child, target, { levelOffset, fromPath });
-    if (renderedChild) {
-      lines.push(renderedChild);
-    }
-  }
-
-  return lines.join("\n");
-}
-
-function createFrontmatter(target) {
-  return `---
-name: ${target.name}
-description: ${target.description}
----
-
-`;
-}
-
-function generateTenzirSkillMd(sitemapRoot, target) {
-  const titleNode = sitemapRoot.children.find((child) => child.level === 1);
-  if (!titleNode) {
-    throw new Error("Could not find the sitemap title in dist/sitemap.md.");
-  }
-
-  const filteredTitleNode = {
-    ...titleNode,
-    children: titleNode.children
-      .map((section) => {
-        const sectionName = extractHeadingText(section.heading ?? "");
-        const maxDepth = sectionName ? SECTION_MAX_LEVEL[sectionName] : null;
-        if (!maxDepth) return null;
-        return filterNode(section, {
-          includeSourcePath: target.includeSourcePath,
-          maxDepth,
-        });
-      })
-      .filter(Boolean),
-  };
-
-  return `${createFrontmatter(target)}${renderNode(filteredTitleNode, target).replace(/\n{3,}/g, "\n\n")}`;
-}
-
-function generateOcsfSkillMd(sitemapRoot, target) {
-  const ocsfNode = findNodeBySourcePath(sitemapRoot, `${OCSF_ROOT}.md`);
-  if (!ocsfNode) {
-    throw new Error("Could not find the OCSF section in dist/sitemap.md.");
-  }
-
-  const renderedOcsfNode = renderNode(ocsfNode, target, {
-    levelOffset: -2,
-    fromPath: "SKILL.md",
-  }).replace(/\n{3,}/g, "\n\n");
-
-  const intro = [
-    "# OCSF Documentation Map",
-    "",
-    "Open Cybersecurity Schema Framework reference extracted from the Tenzir documentation.",
-    "",
-  ].join("\n");
-
-  return `${createFrontmatter(target)}${intro}${renderedOcsfNode}`;
-}
-
-function collectMarkdownFiles(dir, rootDir = dir) {
-  const files = [];
-  const entries = fs.readdirSync(dir, { withFileTypes: true });
-
-  for (const entry of entries) {
-    const fullPath = path.join(dir, entry.name);
-    if (entry.isDirectory()) {
-      files.push(...collectMarkdownFiles(fullPath, rootDir));
-      continue;
-    }
-
-    if (!entry.name.endsWith(".md")) continue;
-
-    files.push(normalizeRelativePath(path.relative(rootDir, fullPath)));
-  }
-
-  return files;
-}
-
-function writeSkillFiles(distPath, outputDir, target, sourcePaths) {
-  let count = 0;
-
-  for (const sourcePath of sourcePaths) {
-    const destPath = target.mapSourcePath(sourcePath);
-    if (!destPath) continue;
-
-    const sourceFile = path.join(distPath, sourcePath);
-    const destFile = path.join(outputDir, destPath);
-    const content = fs.readFileSync(sourceFile, "utf-8");
-    const rewritten = rewriteContent(content, target, destPath);
-
-    fs.mkdirSync(path.dirname(destFile), { recursive: true });
-    fs.writeFileSync(destFile, rewritten);
-    count++;
-  }
-
-  return count;
-}
-
-function fmt(n) {
-  return n.toLocaleString("en-US");
-}
-
-export function buildSkills({ cwd = process.cwd() } = {}) {
-  const distPath = path.join(cwd, "dist");
-  const sitemapPath = path.join(distPath, "sitemap.md");
-
-  if (!fs.existsSync(distPath)) {
-    throw new Error(
-      "dist/ directory not found. Run 'bun run build:full' first.",
-    );
-  }
-
-  if (!fs.existsSync(sitemapPath)) {
-    throw new Error(
-      "dist/sitemap.md not found. Run 'bun run build:full' first.",
-    );
-  }
-
-  const sitemap = fs.readFileSync(sitemapPath, "utf-8");
-  const sitemapRoot = parseHeadingTree(sitemap);
-  const markdownFiles = collectMarkdownFiles(distPath).filter(
-    (filePath) => filePath !== "sitemap.md",
-  );
-
-  const results = [];
-
-  const skillsDir = path.join(cwd, "skills");
-
-  for (const target of SKILL_TARGETS) {
-    const outputDir = path.join(skillsDir, target.name);
-    const sourcePaths = markdownFiles.filter((filePath) =>
-      target.includeSourcePath(filePath),
-    );
-
-    if (sourcePaths.length === 0) {
-      throw new Error(
-        `No markdown files found for the '${target.name}' skill.`,
-      );
-    }
-
-    if (fs.existsSync(outputDir)) {
-      fs.rmSync(outputDir, { recursive: true });
-    }
-    fs.mkdirSync(outputDir, { recursive: true });
-
-    const skillMd =
-      target.name === "tenzir-docs"
-        ? generateTenzirSkillMd(sitemapRoot, target)
-        : generateOcsfSkillMd(sitemapRoot, target);
-    const skillPath = path.join(outputDir, "SKILL.md");
-    fs.writeFileSync(skillPath, skillMd);
-
-    const fileCount = writeSkillFiles(distPath, outputDir, target, sourcePaths);
-    const tokens = Math.round(skillMd.length / 4);
-
-    console.warn(
-      `Generated skills/${target.name}/SKILL.md (${fmt(skillMd.length)} chars, ~${fmt(tokens)} tokens)`,
-    );
-    console.warn(
-      `Copied ${fmt(fileCount)} markdown files to skills/${target.name}/`,
-    );
-    console.warn(
-      `Validate with: (cd skills && skills-ref validate ${target.name})\n`,
-    );
-
-    results.push({
-      name: target.name,
-      outputDir,
-      fileCount,
-      tokens,
-    });
-  }
-
-  return results;
-}
-
-function main() {
-  const results = buildSkills();
-  for (const result of results) {
-    console.warn(`Skill ready at: ${result.outputDir}/`);
-  }
-}
-
-if (
-  process.argv[1] &&
-  import.meta.url === pathToFileURL(process.argv[1]).href
-) {
-  try {
-    main();
-  } catch (error) {
-    console.error(
-      `Error: ${error instanceof Error ? error.message : String(error)}`,
-    );
-    process.exit(1);
-  }
-}

@@ -1,200 +0,0 @@
-/**
- * OCSF client for reading schema data from local files.
- * Requires OCSF_LOCAL_DIR environment variable pointing to the schemas directory.
- */
-
-import { readFile } from "node:fs/promises";
-import { join } from "node:path";
-
-// GitHub API for ocsf-docs repository (still fetched remotely)
-const OCSF_DOCS_API = "https://api.github.com/repos/ocsf/ocsf-docs/contents";
-const OCSF_DOCS_RAW = "https://raw.githubusercontent.com/ocsf/ocsf-docs/main";
-
-/**
- * Get the local schemas directory from environment.
- */
-function getLocalDir() {
-  const dir = process.env.OCSF_LOCAL_DIR;
-  if (!dir) {
-    throw new Error(
-      "OCSF_LOCAL_DIR environment variable is required. " +
-        "Run the build-ocsf action first or set it to your local schemas directory.",
-    );
-  }
-  return dir;
-}
-
-/**
- * Read JSON from a local file.
- */
-async function readLocalJson(filePath) {
-  const content = await readFile(filePath, "utf-8");
-  return JSON.parse(content);
-}
-
-/**
- * Fetch JSON from a URL with timeout (for GitHub API).
- */
-export async function fetchJson(url, timeout = 30000) {
-  const controller = new AbortController();
-  const timeoutId = setTimeout(() => controller.abort(), timeout);
-
-  try {
-    const response = await fetch(url, { signal: controller.signal });
-    if (!response.ok) {
-      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
-    }
-    return await response.json();
-  } finally {
-    clearTimeout(timeoutId);
-  }
-}
-
-/**
- * Fetch text from a URL with timeout (for GitHub API).
- */
-export async function fetchText(url, timeout = 30000) {
-  const controller = new AbortController();
-  const timeoutId = setTimeout(() => controller.abort(), timeout);
-
-  try {
-    const response = await fetch(url, { signal: controller.signal });
-    if (!response.ok) {
-      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
-    }
-    return await response.text();
-  } finally {
-    clearTimeout(timeoutId);
-  }
-}
-
-/**
- * Fetch current/latest OCSF version from local versions.json.
- */
-export async function fetchCurrentVersion() {
-  const versions = await fetchAvailableVersions();
-  // Return the last (latest) version
-  const current = versions[versions.length - 1];
-  console.log(`  Current version: ${current}`);
-  return current;
-}
-
-/**
- * Fetch list of available OCSF versions from local versions.json.
- * Returns versions sorted ascending.
- */
-export async function fetchAvailableVersions() {
-  const localDir = getLocalDir();
-  const versionsFile = join(localDir, "versions.json");
-
-  console.log(`Reading available versions from ${versionsFile}...`);
-  const versions = await readLocalJson(versionsFile);
-
-  // Sort by semantic version (dev versions sort after their base version)
-  versions.sort((a, b) => {
-    const parseVersion = (v) => {
-      const isDev = v.includes("-dev");
-      const clean = v.replace(/-dev$/, "");
-      const [major, minor, patch] = clean.split(".").map(Number);
-      return { major, minor, patch, isDev };
-    };
-    const va = parseVersion(a);
-    const vb = parseVersion(b);
-    return (
-      va.major - vb.major ||
-      va.minor - vb.minor ||
-      va.patch - vb.patch ||
-      (va.isDev === vb.isDev ? 0 : va.isDev ? 1 : -1)
-    );
-  });
-
-  console.log(
-    `  Found ${versions.length} versions: ${versions[0]} to ${versions[versions.length - 1]}`,
-  );
-  return versions;
-}
-
-/**
- * Fetch OCSF schema for a specific version from local files.
- */
-export async function fetchSchema(version) {
-  const localDir = getLocalDir();
-  const schemaFile = join(localDir, version, "schema.json");
-  console.log(`Reading schema from ${schemaFile}...`);
-  return await readLocalJson(schemaFile);
-}
-
-/**
- * Fetch OCSF profiles for a specific version from local files.
- */
-export async function fetchProfiles(version) {
-  const localDir = getLocalDir();
-  const profilesFile = join(localDir, version, "profiles.json");
-  console.log(`Reading profiles from ${profilesFile}...`);
-  return await readLocalJson(profilesFile);
-}
-
-/**
- * Fetch OCSF extensions for a specific version from local files.
- */
-export async function fetchExtensions(version) {
-  const localDir = getLocalDir();
-  const extensionsFile = join(localDir, version, "extensions.json");
-  console.log(`Reading extensions from ${extensionsFile}...`);
-  return await readLocalJson(extensionsFile);
-}
-
-/**
- * Fetch FAQ files from ocsf-docs repository.
- * Returns array of {name, content} objects.
- */
-export async function fetchFaqs() {
-  const faqsResponse = await fetchJson(`${OCSF_DOCS_API}/faqs`);
-  // Filter to only actual FAQ .md files, exclude README and other non-FAQ files
-  const faqFiles = faqsResponse.filter(
-    (f) =>
-      f.name.endsWith(".md") &&
-      f.name.toLowerCase() !== "readme.md" &&
-      !f.name.startsWith("."),
-  );
-
-  const results = [];
-  for (const file of faqFiles) {
-    const content = await fetchText(`${OCSF_DOCS_RAW}/faqs/${file.name}`);
-    results.push({ name: file.name, content });
-  }
-  return results;
-}
-
-/**
- * Fetch article files from ocsf-docs repository.
- * Returns array of {name, content} objects.
- */
-export async function fetchArticles() {
-  const articlesResponse = await fetchJson(`${OCSF_DOCS_API}/articles`);
-  // Filter to only actual article .md files, exclude README and other non-article files
-  const articleFiles = articlesResponse.filter(
-    (f) =>
-      f.name.endsWith(".md") &&
-      f.name.toLowerCase() !== "readme.md" &&
-      !f.name.startsWith("."),
-  );
-
-  const results = [];
-  for (const file of articleFiles) {
-    const content = await fetchText(`${OCSF_DOCS_RAW}/articles/${file.name}`);
-    results.push({ name: file.name, content });
-  }
-  return results;
-}
-
-/**
- * Fetch the OCSF overview document (understanding-ocsf.md).
- * Returns {name, content} object.
- */
-export async function fetchOverview() {
-  const content = await fetchText(
-    `${OCSF_DOCS_RAW}/overview/understanding-ocsf.md`,
-  );
-  return { name: "understanding-ocsf.md", content };
-}

@@ -1,1425 +0,0 @@
-/**
- * MDX generators for OCSF reference documentation.
- */
-
-// =============================================================================
-// Shared Helpers
-// =============================================================================
-
-/**
- * Convert version string to URL-safe slug (1.7.0 -> 1-7-0).
- */
-export function versionToSlug(version) {
-  return version.replace(/\./g, "-");
-}
-
-/**
- * Convert OCSF name to URL-safe slug (win/reg_key -> win_reg_key).
- */
-export function nameToSlug(name) {
-  return name.replace(/\//g, "_");
-}
-
-/**
- * Clean HTML tags from description text, converting to Markdown.
- */
-export function cleanDescription(text) {
-  if (!text) return "";
-  return (
-    text
-      // Convert code tags
-      .replace(/<code>/g, "`")
-      .replace(/<\/code>/g, "`")
-      // Convert external links (with protocol) to markdown
-      .replace(
-        /<a[^>]*href=['"](https?:\/\/[^'"]+)['"][^>]*>([^<]+)<\/a>/g,
-        "[$2]($1)",
-      )
